INSERT INTO `Movie` (`name`, `year`, `length`, `description`, `director`, `id_category`, `image`, `trailer`, `min_age`) VALUES
("Interstellar", 2014, 169, "Un groupe d’explorateurs voyage à travers un trou de ver pour sauver l’humanité.", "Christopher Nolan", 4, "interstellar.jpg", "https://www.youtube.com/embed/VaOijhK3CRU?si=76Ke4uw4LYjuLuQ6", 12),
("La Liste de Schindler", 1993, 195, "Un industriel allemand sauve des milliers de Juifs pendant l’Holocauste.", "Steven Spielberg", 3, "schindler.webp", "https://www.youtube.com/embed/ONWtyxzl-GE?si=xC3ASGGPy5Ib-aPn", 16),
("Your Name", 2016, 107, "Deux adolescents échangent leurs corps de manière mystérieuse.", "Makoto Shinkai", 5, "your_name.jpg", "https://www.youtube.com/embed/AROOK45LXXg?si=aUQyGk2VMCb_ToUL", 10),
("Le Bon, la Brute et le Truand", 1966, 161, "Trois hommes se lancent à la recherche d’un trésor caché.", "Sergio Leone", 13, "bon_brute_truand.jpg", "https://www.youtube.com/embed/WA1hCZFOPqs?si=TwNZAoM4oj4KpGja", 12);
("À la croisée des mondes : La Boussole d’or",	2007,	113,	"Dans un monde parallèle où l’âme humaine prend la forme d’un animal familier, une courageuse orpheline nommée Lyra voyage vers le Grand Nord pour sauver ses amis kidnappés et percer le mystère d’une particule cosmique appelée la Poussière.",	"Chris Weitz",	9,	"a_la_croisee_des_mondes-la_boussole_dor.jpg", "https://www.youtube.com/embed/LHYoOGfBObU?si=f0g7gMp_RjwBCYA5",	10),
("Apex",	2026,	135,	"Sasha pratique l’escalade de haut niveau. Frappée par un deuil, elle tente de se changer les idées en grimpant sur des falaises en forêt. Elle est alors prise en chasse par un braconnier inconnu. Tout en luttant contre les éléments naturels, elle va devoir affronter cet ennemi mystérieux. Elle ne pourra pas compter sur l’aide de son partenaire.",	"Baltasar Kormákur",	1,	"apex.jpg",	"https://www.youtube.com/watch?v=ELJ_orzMy1M",	16),
("Arthur et les Minimoys",	2006,	94,	"Un garçon découvre un monde miniature et part à l’8 pour sauver sa maison.",	"Luc Besson",	5,	"arthur_et_les_minimoys.jpg",	"https://www.youtube.com/watch?v=xMP0WpiFHCE",	0),
("Astérix et Obélix : Mission Cléopâtre",	2002,	107,	"Cléopâtre, piquée au vif par Jules César qui dénigre la grandeur de son peuple, lui lance un défi : construire en trois mois un palais somptueux qui prouvera la supériorité de la civilisation égyptienne. Elle confie cette mission impossible à l’architecte Numérobis, menacé d’être jeté aux crocodiles en cas d’échec. Conscient de l’ampleur du chantier, Numérobis part chercher de l’aide en Gaule auprès du druide Panoramix, accompagné d’Astérix et Obélix. Ensemble, ils se rendent en Égypte pour accélérer la construction grâce à la potion magique. Mais Amonbofis, architecte rival jaloux, multiplie les sabotages, parfois avec l’appui des Romains. Entre complots, grèves, poursuites, pièges et affrontements, les Gaulois doivent déjouer tous les obstacles pour permettre à Numérobis de terminer le palais dans les temps. Leur réussite forcera César à reconnaître publiquement la grandeur du peuple égyptien.",	"Alain Chabat",	2,	"asterix_et_obelix_mission_cleopatre.jpg",	"https://www.youtube.com/embed/7Nd1ZCwB5PI?si=XBkpY0JI_AbEF2n7",	0),
("Bee Movie",	2007,	91,	"Une abeille intente un procès contre les humains pour exploitation du miel.",	"Simon J. Smith, Steve Hickner",	5,	"bee_movie.jpg",	"https://www.youtube.com/watch?v=jJw4UyV21qU",	0),
("Blade Runner 2049",	2017,	163,	"En 2049, la société est fragilisée par les nombreuses tensions entre les humains et leurs esclaves créés par bio-ingénierie. L’officier K est un Blade Runner: il fait partie d’une force d’intervention d’élite chargée de trouver et d’éliminer ceux qui n’obéissent pas aux ordres des humains.",	"Denis Villeneuve",	4, "blade_runner_2049.jpg",	"https://youtu.be/O4C5cwSbXZ8?si=pE1F4vJTC72quGIw",	0),
("Bullet Train", 2022,	127,	"Coccinelle est un assassin malchanceux et particulièrement déterminé à accomplir sa nouvelle mission paisiblement après que trop d’entre elles aient déraillé. Mais le destin en a décidé autrement et l’embarque dans le train le plus rapide au monde aux côtés d’adversaires redoutables qui ont tous un point commun, mais dont les intérêts divergent radicalement... Il doit alors tenter par tous les moyens de descendre du train.", 	"David Leitch",	2,	"bullet_train.jpg",	"https://www.youtube.com/watch?v=N9W-5g6Zp2s",	12),
("Citizenfour",	2014,	114,	'En 2013, Laura Poitras reçoit des e-mails cryptés d’un mystérieux "CITIZENFOUR" qui prétend détenir des preuves de programmes de surveillance illégaux menés par la NSA. Elle se rend à Hong Kong avec les journalistes Glenn Greenwald et Ewen MacAskill pour rencontrer l’informateur, qui s’avère être Edward Snowden. Le film capture en temps réel les révélations qui ont secoué le monde et les conséquences immédiates pour Snowden.',	"Laura Poitras",	10,	"citizenfour.jpg",	"https://youtu.be/_VD7nnONpJE?si=ERcN2i3Bl5PigHHB",	0),
("Conjuring 1 : les dossiers Warren",	2013,	112,	"Avant Amityville, il y avait Harrisville… Conjuring : Les dossiers Warren, raconte l’histoire horrible, mais vraie, d’Ed et Lorraine Warren, enquêteurs paranormaux réputés dans le monde entier, venus en aide à une famille terrorisée par une présence inquiétante dans leur ferme isolée… Contraints d’affronter une créature démoniaque d’une force redoutable, les Warren se retrouvent face à l’affaire la plus terrifiante de leur carrière…",	"James Wan",	7,	"conjuring1.jpg",	"https://www.youtube.com/watch?v=Mkf9rGLXeuE",	12),
("Conjuring 2 : le cas Enfield", 	2016,	134,	"Les époux Warren se rendent dans la banlieue de Londres à la demande d’un prêtre afin de s’occuper du cas de Janet, une petite fille de 11 ans possédée par un démon. Peggy, la mère de Janet, ainsi que les soeurs de la fillette, sont terrifiées. Ed et Lorraine se rendent rapidement compte que l’affaire est sérieuse, et surtout, qu’ils ne sont pas là par hasard. L’entité qui a pris possession de Janet les connaît, et les hait assez pour vouloir les éliminer. Le second épisode d’une franchise d’7 dont la réussite ne repose pas uniquement sur sa capacité à faire sursauter le spectateur. Les décors, la musique, les effets sonores : tout concourt à placer le public dans une ambiance sinistre à souhait.", 	"James Wan",	7,	"conjuring2.jpg",	"https://www.youtube.com/watch?v=Y3kNhv0Nm_g",	12),
("Conjuring 3 : Sous l’emprise du Diable",	2021,	112,	"Conjuring 3 : sous l’emprise du diable retrace une affaire terrifiante de meurtre et de présence maléfique mystérieuse qui a même ébranlé les enquêteurs paranormaux Ed et Lorraine Warren, pourtant très aguerris. Dans cette affaire issue de leurs dossiers secrets – l’une des plus spectaculaires – , Ed et Lorrain commencent par se battre pour protéger l’âme d’un petit garçon, puis basculent dans un monde radicalement inconnu. Ce sera la première fois dans l’histoire des États-Unis qu’un homme soupçonné de meurtre plaide la possession démoniaque comme ligne de défense.",	"Michael Chaves",	7,	"conjuring3.jpg",	"https://www.youtube.com/watch?v=YjN7cRbaZzE",	12),
("Conjuring 4 : L’Heure du jugement", 2025,	135,	"Alors qu’ils espéraient une nouvelle vie, Ed et Lorraine Warren se voient impliqués dans une dernière enquête… qu’ils n’auraient jamais dû accepter. Dans la maison de la famille Smurl, un mal ancien les attend. Un ennemi qu’ils croyaient à jamais enfoui... Découvrez comment les Warren ont affronté le cas le plus maléfique de leur carrière, inspiré de faits réels qui ont terrorisé l’Amérique.", 	"Michael Chaves", 	7,	"conjuring4.jpg",	"https://www.youtube.com/watch?v=pANEpIq6UZI",	12),
("Coraline",	2009,	100,	'Coraline Jones est une fillette intrépide qui découvre une porte secrète dans sa nouvelle maison. Elle débouche sur un monde parallèle qui ressemble étrangement au sien, mais en mieux. Cependant, cette 8 fantastique devient dangereuse quand sa "Mère" tente de la garder prisonnière à jamais.',	"Henry Selick", 9,	"coraline.jpg",	"https://www.youtube.com/watch?v=8CC7-5sYJv8",	0),
("Danse avec les loups",	1990,	236,	'Le jeune lieutenant John Dunbar est envoyé à un poste de reconnaissance dans les immenses plaines du Dakota pendant la guerre de Sécession. Il rencontre au cours de l’une de ses missions de reconnaissance le peuple sioux. Le lieutenant se lie d’amitié avec la population indienne. Il arrive même à intégrer la tribu, au point d’être surnommé "Danse avec les loups", et de s’éprendre d’une des leurs, une blanche baptisée "Dressée avec le poing".', 	"Kevin Costner",	13, "danse_avec_les_loups.jpg",	"https://www.youtube.com/watch?v=dbYwm6IBq54",	0),
("Demon Slayer : La Forteresse Infinie Film 1", 2025,	155,	"Tanjirô Kamado a rejoint une organisation dédiée à la chasse aux démons, les pourfendeurs de démons, après que sa jeune sœur Nezuko ait été transformée en démon. Devenant de plus en plus fort et proche des autres membres de l’armée, Tanjirô affronte de nombreux démons en compagnie de ses camarades, Zen’itsu Agatsuma et Inosuke Hashibira. Ses 8s l’ont amené à se battre aux côtés des combattants les plus hauts placés de l’armée des pourfendeurs de démons, les piliers, tels que le pilier de la flamme, Kyôjurô Rengoku, dans le train de l’infini, le pilier du son, Tengen Uzui, dans le quartier des plaisirs, ainsi que le pilier de la brume, Muichirô Tokitô, et le pilier de l’amour, Mitsuri Kanroji, dans le village des forgerons. Alors que l’armée des pourfendeurs de démons et les piliers s’exerçaient lors d’une session d’entraînement en prévision du futur affrontement contre les démons, Muzan Kibutsuji fait son apparition au manoir Ubuyashiki. Le responsable de l’armée étant en danger, Tanjirô et les piliers se ruent vers le quartier général, mais tombent dans le piège tendu par Muzan Kibutsuji et se retrouvent coincés dans les profondeurs d’un espace mystérieux. Tanjirô et le reste de l’armée des pourfendeurs de démons sont téléportés dans le bastion des démons : la Forteresse infinie. C’est là que s’embrasera l’ultime combat entre l’armée des pourfendeurs de démons et les forces démoniaques.", 	"Haruo Sotozaki", 	5,	"demon_slayer-la_forteresse_infinie.jpg",	"https://www.youtube.com/watch?v=KiWTr1AQ33M",	12),
("Django Unchained",	2012,	165,	"Dans le sud des États-Unis, deux ans avant la guerre de Sécession, le chasseur de primes d’origine allemande, le Dr King Schultz, fait l’acquisition de Django, un esclave qui peut l’aider à traquer les frères Brittle. En échange, Schultz promet de libérer Django et de l’aider à retrouver sa femme, Broomhilda, retenue par le redoutable propriétaire d’une plantation, Calvin Candie.",	"Quentin Tarantino",	1, "django_unchained.jpg",	"https://www.youtube.com/watch?v=K2XjgsfzDrU",	16),
("Dragons",	2010,	98,	"Un jeune Viking se lie d’amitié avec un dragon, changeant la vision de son peuple.",	"Chris Sanders, Dean DeBlois",	9,	"dragons1.jpg",	"https://www.youtube.com/watch?v=d0grS8PYUn0",	0),
("Dragons", 2025,	125,	"Sur l’île escarpée de Beurk, où depuis des générations Vikings et dragons s’affrontent sans merci, Harold fait figure d’exception. Effacé, écrasé par la stature de son père, le chef de la tribu, Stoïk, ce jeune rêveur défie des siècles de tradition en se liant d’amitié avec un dragon nommé Krokmou. Leur lien improbable va révéler la vraie nature des dragons et remettre en question les fondements mêmes de la société viking. Flanqué de la farouche Astrid et de Gueulfor, le sympathique forgeron du village, Harold va devoir s’imposer dans un monde déchiré par la peur et l’incompréhension. Alors qu’une dangereuse créature réémerge des brumes du passé, menaçant à la fois les Vikings et les dragons, l’amitié d’Harold et Krokmou pourrait bien être la clef d’un nouvel avenir. Ensemble, ils vont devoir se frayer un chemin fragile vers la paix, en dépassant les limites de leurs deux mondes pour mieux redéfinir les notions de chef et de héros.",	"Dean DeBlois",	9,	"dragons_live1.jpg",	"https://www.youtube.com/watch?v=seY55AKGmxQ",	0),
("Dragons 2",	2014,	102,	"Tandis qu’Astrid, Rustik et le reste de la bande se défient durant des courses sportives de dragons devenues populaires sur l’île, notre duo désormais inséparable parcourt les cieux, à la découverte de territoires inconnus et de nouveaux mondes. Au cours de l’une de leurs 8s, ils découvrent une grotte secrète qui abrite des centaines de dragons sauvages, dont le mystérieux Dragon Rider. Les deux amis se retrouvent alors au centre d’une lutte visant à maintenir la paix. Harold et Krokmou vont se battre pour défendre leurs valeurs et préserver le destin des hommes et des dragons.", "Dean DeBlois",	9,	"dragons2.jpg",	"https://www.youtube.com/watch?v=lm4ApfTrLKs",	0),
("Dragons 3 : Le Monde Caché",	2019,	104,	"Harold est maintenant le chef de Berk au côté d’Astrid et Krokmou, en tant que dragon, est devenu le leader de son espèce. Ils réalisent enfin leurs rêves de vivre en paix entre vikings et dragons. Mais lorsque l’apparition soudaine d’une Furie Eclair coïncide avec la plus grande menace que le village n’ait jamais connue, Harold et Krokmou sont forcés de quitter leur village pour un voyage dans un monde caché dont ils n’auraient jamais soupçonnés l’existence. Alors que leurs véritables destins se révèlent, dragons et vikings vont se battre ensemble jusqu’au bout du monde pour protéger tout ce qu’ils chérissent.",	"Dean DeBlois",	9,	"dragons3.jpg",	"https://www.youtube.com/watch?v=lNYDeG4Qd4k",	0),
("Fantastic Mr. Fox",	2009,	87,	"Un renard rusé vole les fermiers voisins, mettant sa famille en danger.",	"Wes Anderson",	5,	"fantastic_mr_fox.jpg",	"https://www.youtube.com/watch?v=_AyJLSef4y4",	0),
("Five Nights At Freddy’s",	2023,	109,	"Mike, jeune homme perturbé, s’occupe de sa sœur Abby, âgée de 10 ans. Il est toujours hanté par la disparition, jamais élucidée, de son petit frère, survenue il y a une dizaine d’années. Récemment licencié, il a absolument besoin de retrouver un emploi pour ne pas perdre la garde d’Abby. Il accepte donc un poste de gardien de nuit, dans un restaurant désaffecté : Freddy Fazbear’s Pizzeria. Mais Mike ne tarde pas à comprendre que les apparences y sont terriblement trompeuses. Avec l’aide de Vanessa Shelly, agent de police, il est confronté, la nuit, à des phénomènes surnaturels inexplicables et bascule dans un univers cauchemardesque...", "Emma Tammi", 	7,	"fnaf.jpg",	"https://www.youtube.com/watch?v=iUgc6N37QmU",	12),
("Five Nights at Freddy's 2", 2025,	104,	"Un an après l'enfer surnaturel de la pizzéria de Freddy Fazbear, un nouveau chapitre de terreur débute lorsqu'Abby, la sœur de l'ex-gardien de sécurité Mike, part à la recherche de ses amis animatroniques : Freddy, Bonnie, Chica et Foxy. Alors que les événements terrifiants s'enchaînent, des secrets sur les origines de Freddy surgissent et déclenchent une 7 disparue depuis des décennies.", "Emma Tammi",	7, "fnaf2.jpg",	"https://www.youtube.com/watch?v=3SzKVYbCOks",	12),
("Forrest Gump",	1994,	142,	"Quelques décennies d'histoire américaine, des années 1940 à la fin du XXème siècle, à travers le regard et l'étrange odyssée d'un homme simple et pur, Forrest Gump.", 	"Robert Zemeckis", 	3,	"forrest_gump.jpg",	"https://www.youtube.com/watch?v=q2AP7dAeVhw",	0),
("Gladiator",	2000,	155,	"Le général romain Maximus est le plus fidèle soutien de l'empereur Marc Aurèle, qu'il a conduit de victoire en victoire avec une bravoure et un dévouement exemplaires. Jaloux du prestige de Maximus, et plus encore de l’amour que lui voue l’empereur, le fils de MarcAurèle, Commode, s’arroge brutalement le pouvoir, puis ordonne l’arrestation du général et son exécution. Maximus échappe à ses assassins mais ne peut empêcher le massacre de sa famille. Capturé par un marchand d’esclaves, il devient gladiateur et prépare sa vengeance.", "Ridley Scott",	11, "gladiator1.jpg",	"https://www.youtube.com/watch?v=ChcgxBAzrks",	0),
("Gladiator II",	2024,	148,	"Des années après avoir assisté à la mort du héros vénéré Maximus aux mains de son oncle, Lucius est forcé d’entrer dans le Colisée lorsque son pays est conquis par les empereurs tyranniques qui gouvernent désormais Rome d’une main de fer. La rage au cœur et l’avenir de l’Empire en jeu, Lucius doit se tourner vers son passé pour trouver la force et l’honneur de rendre la gloire de Rome à son peuple.", 	"Ridley Scott", 11,	"gladiator2.jpg",	"https://www.youtube.com/watch?v=APv2lidaDmo",	12),
("Hannibal : Le Cauchemar de Rome", 	2006,	89,	'"Je jure qu’aussi longtemps que je vivrai, je demeurerai un ennemi de Rome." Depuis l’enfance, sa vie fut consacrée à la destruction du plus grand empire que le monde ait connu. Hannibal, le plus grand ennemi de Rome raconte l’extraordinaire épopée du seul homme qui ait fait plier la puissance de Rome.', 	"Edward Bazalgette",	10,	"hannibal_le_cauchemar_de_rome.jpg",	"https://www.youtube.com/watch?v=POIZn7Hk_Mg&t=2s",	10),
("I Robot", 2004,	115,	"Un policier enquête sur un robot impliqué dans un meurtre malgré les lois de la robotique.",	"Alex Proyas",	4,	"i_robot.jpg",	"https://www.youtube.com/watch?v=PjECS38ZGWE",	10),
("Il était une fois dans l’Ouest",	1968,	165,	"Alors qu’il prépare une fête pour sa femme, Bet McBain est tué avec ses trois enfants. Jill McBain hérite des terres de son mari, convoitées par Morton, le commanditaire du crime, car elles prennent de la valeur avec l’arrivée imminente du chemin de fer. Cependant, les soupçons se portent sur un aventurier, Cheyenne...",	"Sergio Leone",	13, "il_etait_une_fois_dans_louest.jpg",	"https://www.youtube.com/watch?v=Gmnxd5QD2uo",	0),
("Inception", 	2010,	158,	"Dom Cobb est un voleur expérimenté – le meilleur qui soit dans l’art périlleux de l’extr1 : sa spécialité consiste à s’approprier les secrets les plus précieux d’un individu, enfouis au plus profond de son subconscient, pendant qu’il rêve et que son esprit est particulièrement vulnérable. Très recherché pour ses talents dans l’univers trouble de l’espionnage industriel, Cobb est aussi devenu un fugitif traqué dans le monde entier qui a perdu tout ce qui lui est cher. Mais une ultime mission pourrait lui permettre de retrouver sa vie d’avant – à condition qu’il puisse accomplir l’impossible : l’inception. Au lieu de subtiliser un rêve, Cobb et son équipe doivent faire l’inverse : implanter une idée dans l’esprit d’un individu. S’ils y parviennent, il pourrait s’agir du crime parfait. Et pourtant, aussi méthodiques et doués soient-ils, rien n’aurait pu préparer Cobb et ses partenaires à un ennemi redoutable qui semble avoir systématiquement un coup d’avance sur eux. Un ennemi dont seul Cobb aurait pu soupçonner l’existence.", "Christopher Nolan",	6,	"inception.jpg",	"https://www.youtube.com/watch?v=HcoZbHBDHQA",	0),
("Independence Day",	1996,	145,	"L’humanité affronte une invasion extraterrestre destructrice.",	"Roland Emmerich",	4,	"independance_day.jpg",	"https://www.youtube.com/watch?v=lYaVIrVB9x8",	10),
("Inglourious Basterds",	2009,	153,	'Dans la France occupée, Shosanna Dreyfus assiste à l’exécution de sa famille par le colonel nazi Hans Landa. Elle parvient à s’échapper et s’enfuit à Paris où elle devient propriétaire d’un cinéma. Ailleurs en Europe, le lieutenant Aldo Raine forme un groupe de soldats juifs américains pour mener des 1s punitives particulièrement sanglantes contre les nazis. "Les Bâtards", comme l’ennemi les surnomme, se joignent à l’actrice allemande et agent secret Bridget von Hammersmark pour tenter d’éliminer les hauts dignitaires du Troisième Reich lors d’une première de film dans le cinéma de Shosanna. Leurs destins vont se croiser lors d’une soirée qui pourrait bien changer le cours de l’Histoire.',	"Quentin Tarantino",	1,	"inglourious_basterds.webp",	"https://www.youtube.com/watch?v=BiPUoLI9eGM",	16),
("James Bond Skyfall",	2012,	143,	"Lorsqu’une mission tourne mal à Istanbul, James Bond est porté disparu et présumé mort. Peu après, le MI6 subit une attaque informatique qui vise directement M, révélant qu’un ennemi intime connaît ses secrets et cherche à la détruire. Bond réapparaît et reprend du service malgré une condition physique affaiblie, déterminé à identifier l’auteur de ces attaques.  Son enquête le mène jusqu’à Raoul Silva, ancien agent du MI6 devenu cyber‑terroriste, animé par une vengeance personnelle contre M. Pour protéger son service et affronter ce passé qui ressurgit, Bond doit repousser ses limites et revenir sur les traces de son enfance, jusqu’au manoir familial de Skyfall, où se joue l’affrontement final.", "Sam Mendes", 1,	"james_bond_skyfall.jpg",	"https://www.youtube.com/watch?v=WKzm6AZFbdc",	12),
("John Wick : Chapitre 1",	2014,	101,	"Depuis la mort de sa femme bien-aimée, John Wick passe ses journées à retaper sa Ford Mustang de 1969, avec pour seule compagnie sa chienne Daisy. Il mène une vie sans histoire, jusqu’à ce qu’un malfrat sadique nommé Iosef Tarasof remarque sa voiture. John refuse de la lui vendre. Iosef n’acceptant pas qu’on lui résiste, s’introduit chez John avec deux complices pour voler la Mustang, et tuer sauvagement Daisy… John remonte la piste de Iosef jusqu’à New York. Un ancien contact, Aurelio, lui apprend que le malfrat est le fils unique d’un grand patron de la pègre, Viggo Tarasof. La rumeur se répand rapidement dans le milieu : le légendaire tueur cherche Iosef. Viggo met à prix la tête de John : quiconque l’abattra touchera une énorme récompense. John a désormais tous les assassins de New York aux trousses.",	"Chad Stahelski",	1,	"john_wick1.jpg",	"https://www.youtube.com/watch?v=pWK5crMuhHY",	12),
("John Wick : Chapitre 2",	2017,	122,	"John Wick est forcé de sortir de sa retraite volontaire par un de ses ex-associés qui cherche à prendre le contrôle d’une mystérieuse confrérie de tueurs internationaux. Parce qu’il est lié à cet homme par un serment, John se rend à Rome, où il va devoir affronter certains des tueurs les plus dangereux du monde.", 	"Chad Stahelski",	1,	"john_wick2.jpg",	"https://www.youtube.com/watch?v=_QtgfA8PjAw",	12),
("John Wick : Chapitre 3",	2019,	130,	"John Wick est en fuite après avoir enfreint la règle suprême du Continental : tuer un homme dans l’enceinte de l’hôtel. Déclaré excommunicado, il perd tous ses droits, son accès aux services du monde criminel et voit sa tête mise à prix pour 14 millions de dollars.  Traqué par des assassins du monde entier, il tente de survivre tout en cherchant un moyen d’effacer sa condamnation. Son parcours le mène de New York au Maroc, où il affronte de nouveaux ennemis et sollicite d’anciens alliés.",	"Chad Stahelski",	1,	"john_wick3.webp",	"https://www.youtube.com/watch?v=Cs4wKxXjkc8",	12),
("John Wick : Chapitre 4",	2023,	169,	"John Wick poursuit sa lutte contre la Grande Table, l’organisation toute‑puissante qui régit le monde criminel. Alors qu’une nouvelle figure d’autorité, le Marquis de Gramont, reçoit les pleins pouvoirs pour éliminer Wick, ce dernier doit affronter des assassins toujours plus nombreux et déterminés. Pour retrouver sa liberté, John se tourne vers d’anciens alliés, voyageant entre New York, Osaka, Berlin et Paris. Chaque étape le rapproche d’un duel final qui pourrait enfin briser le cycle de violence… ou l’achever définitivement.", "Chad Stahelski",	1,	"john_wick4.webp",	"https://www.youtube.com/watch?v=6itn_8L6-Z8",	12),
